SELECT third_party_name
FROM third_party_categories
WHERE compliance_status = 'compliant';

SELECT SUM(data_quantity) AS total_data_collected
FROM personal_info_collection
WHERE category_id = 0;

SELECT COUNT(*) AS total_completed_requests
FROM data_subject_requests
WHERE status = 'completed';

SELECT COUNT(*) AS total_permanent_opt_outs
FROM opt_outs
WHERE is_permanent = 1;

SELECT category_id, SUM(data_quantity) AS total_data_collected
FROM personal_info_collection
GROUP BY category_id;

SELECT customer_id
FROM opt_outs
WHERE reason = 'Privacy concerns';

SELECT COUNT(*) AS required_category_count
  FROM personal_info_categories
  WHERE is_required = 1;

SELECT category_name
FROM personal_info_categories
WHERE is_required = 1;
